def process_graph(graph_data):

    # Create a copy of the graph to avoid modifying the original
    graph_copy = graph_data.copy()

    # Find the CONTROL_DOMAIN node with name 'ju1.a1.dom'
    control_domain_node = None
    for node in graph_copy.nodes(data=True):
        if node[1]['name'] == 'ju1.a1.dom' and 'EK_CONTROL_DOMAIN' in node[1]['type']:
            control_domain_node = node[0]
            break

    if control_domain_node is None:
        return {
            'type': 'text',
            'data': 'Control domain node not found',
            'updated_graph': nx.readwrite.json_graph.node_link_data(graph_copy)
        }

    # Find all child nodes connected to this control domain via RK_CONTAINS edges
    child_nodes = []
    for edge in graph_copy.edges(data=True):
        if edge[0] == control_domain_node and edge[2]['type'] == 'RK_CONTAINS':
            child_nodes.append(edge[1])

    # Calculate total physical capacity for each child node
    results = []
    for child_node in child_nodes:
        total_capacity = 0

        # Get all PORT nodes under this child node (using hierarchy)
        # We need to traverse down to find all PORTs
        visited = set()
        queue = [child_node]

        while queue:
            current_node = queue.pop(0)
            if current_node in visited:
                continue
            visited.add(current_node)

            current_node_data = graph_copy.nodes[current_node]

            # If it's a PORT node, add its capacity
            if 'EK_PORT' in current_node_data['type']:
                total_capacity += current_node_data.get('physical_capacity_bps', 0)

            # Add children of current node to queue
            for edge in graph_copy.out_edges(current_node, data=True):
                if edge[2]['type'] == 'RK_CONTAINS':
                    queue.append(edge[1])

        results.append((current_node_data['name'], total_capacity))

    # Sort by total physical capacity in descending order
    results.sort(key=lambda x: x[1], reverse=True)

    return {
        'type': 'list',
        'data': results,
        'updated_graph': nx.readwrite.json_graph.node_link_data(graph_copy)
    }

